function safeMoneyValue(n) {
  try { return money(n); } catch (e) { return "$" + Math.round(Number(n) || 0).toLocaleString(); }
}
function showSaveIndicator() {
  let el = document.getElementById("ledger-save-indicator");
  if (!el) {
    el = document.createElement("div");
    el.id = "ledger-save-indicator";
    el.className = "ledger-save-indicator";
    el.textContent = "💾 saved";
    document.body.appendChild(el);
  }
  el.classList.add("show");
  clearTimeout(ledgerSaveTimer);
  ledgerSaveTimer = setTimeout(() => el.classList.remove("show"), 950);
}
function flashDelta(label, value, kind = "stat") {
  if (!state || !value) return;
  const el = document.createElement("div");
  const goodForNegative = ["stress", "debt"].includes(label);
  const isGood = kind === "money" ? value > 0 : (goodForNegative ? value < 0 : value > 0);
  el.className = `ledger-delta-float ${kind === "money" ? "money" : (isGood ? "good" : "bad")}`;
  const sign = value > 0 ? "+" : "";
  el.textContent = kind === "money" ? `${sign}${safeMoneyValue(value)}` : `${cap(label)} ${sign}${value}`;
  el.style.top = (78 + Math.floor(Math.random() * 70)) + "px";
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 1250);
}
function showStatDeltas(deltas) {
  Object.entries(deltas || {}).forEach(([k, v], idx) => {
    if (!v) return;
    setTimeout(() => flashDelta(k, v, ["money", "ira", "retirement401k"].includes(k) ? "money" : "stat"), idx * 70);
  });
}
function legacyNetWorth(s = state) {
  if (!s) return 0;
  // Migrate legacy rentals into the v18.62 real-estate portfolio first so they aren't counted
  // twice (the migration clears s.rentals), then count property as live equity below.
  try { if (typeof window.reEnsureV1862 === "function") window.reEnsureV1862(); } catch (e) {}
  const reEquityNW = (typeof window.reEquityV1862 === "function") ? Math.max(0, Number(window.reEquityV1862()) || 0) : 0;
  // Car garage (v18.67): ensure migrates the legacy state.car into the garage (and clears s.car), then
  // count garage equity (resale value - loans). After migration carsValue below is 0 (no double count).
  try { if (typeof window.carEnsureV1867 === "function") window.carEnsureV1867(); } catch (e) {}
  const carEquityNW = (typeof window.carEquityV1867 === "function") ? (Number(window.carEquityV1867()) || 0) : 0;
  const f = s.finance || {};
  const debts = f.debts || {};
  const stocks = f.stocksV18 || {};
  const firm = f.personalFirm || f.personalFund || {};
  const home = homes.find(h => h.id === s.home);
  const ownedHome = home && home.price ? home.price : 0;
  const carsValue = cars.find(c => c.id === s.car)?.price || 0;
  const rentalValue = (s.rentals || []).reduce((sum, id) => sum + (rentals.find(r => r.id === id)?.price || 0), 0);
  const newBizValue = (f.bizV1860 && Array.isArray(f.bizV1860.businesses))
    ? f.bizV1860.businesses.reduce((sum, b) => {
        if (!b || b.active === false || b.dead) return sum;
        // Public companies: count only the player's tradable stake (shares x live
        // price) so it moves with the share price and never double-counts.
        if (b.public && b.shareTicker) {
          const st = f.stocksV18 || {};
          const h = (st.holdings || []).find(x => x && x.id === b.shareTicker);
          const price = Number((st.prices || {})[b.shareTicker]) || Number(b._ipoPrice) || 0;
          return sum + Math.max(0, (h ? Number(h.shares) || 0 : 0) * price);
        }
        return sum + Math.max(0, Number(b.valuation || b.value || 0) || 0) + Math.max(0, Number(b.cashInBusiness || b.companyCash || 0) || 0);
      }, 0)
    : 0;
  // Family trust corpus + child trust funds + estate trust cash are real protected assets;
  // count them so funding the trust does not make net worth drop. (Matches finance-ledger.)
  const ft = f.familyTrustV1839 || {};
  const trustFundsTotal = (f.trustFunds && typeof f.trustFunds === "object")
    ? Object.keys(f.trustFunds).reduce((sum, k) => sum + (Number(f.trustFunds[k]) || 0), 0) : 0;
  const trustAssets =
    Math.max(0, Number(ft.corpus) || 0) +
    Math.max(0, trustFundsTotal) +
    Math.max(0, Number(s.estateV1831 && s.estateV1831.assets && s.estateV1831.assets.trustCash) || 0);
  const assets =
    (Number(s.money) || 0) + (Number(s.savings) || 0) + (Number(s.ira) || 0) + (Number(s.retirement401k) || 0) +
    (Number(f.superSaver) || 0) + (Number(f.brokerage) || 0) + (Number(f.brokerageCash) || 0) +
    (Number(stocks.marketValue) || Number(stocks.value) || Number(f.stockValue) || Number(f.realStocksValue) || Number(f.marketValue) || 0) +
    (Number(f.managedPortfolio) || 0) + (Number(f.externalManager && f.externalManager.capital) || 0) +
    (Number(f.managerFirmsV1829 && f.managerFirmsV1829.capital) || 0) +
    (Number(f.personalFirmCash) || Number(f.firmCashV1828) || Number(f.firmCash) || 0) +
    (Number(firm.cash) || Number(firm.managed) || Number(firm.capital) || Number(firm.balance) || Number(firm.account) || 0) +
    ownedHome + carsValue + rentalValue + reEquityNW + carEquityNW +
    newBizValue + trustAssets +
    ((f.businesses || []).reduce ? (f.businesses || []).reduce((sum, b) => (b && (b._migratedToBizV1861 || b.founderActiveV1860)) ? sum : sum + Math.max(0, Number(b.value) || 0) + Math.max(0, Number(b.retainedEarnings) || 0), 0) : 0);
  const debt =
    (Number(s.debt) || 0) + (Number(f.creditCardDebt) || 0) + (Number(f.assetBackedLoan) || 0) +
    (Number(f.taxDebt) || 0) + (Number(f.medicalDebt) || 0) + (Number(f.schoolDebt) || Number(f.educationDebt) || 0) +
    (Number(f.securedDebt) || 0) + (Number(debts.medical) || 0) + (Number(debts.education) || 0) + (Number(debts.secured) || 0);
  return Math.round(assets - debt);
}
function ledgerLegacyScore(s = state) {
  if (!s) return 0;
  const children = Object.values(s.relationships || {}).filter(r => r.role === "Child").length;
  const careerBonus = s.job ? Math.round((s.job.salary || 0) / 2500) : 0;
  return Math.max(0, Math.round(
    (s.age || 0) * 10 +
    children * 120 +
    Math.max(0, legacyNetWorth(s)) / 8000 +
    (s.stats?.karma || 0) * 3 +
    (s.fame || 0) * 6 +
    careerBonus
  ));
}
function ensureLegacyShape() {
  if (!state) return;
  state.legacy ||= {};
  state.legacy.generation ||= 1;
  state.legacy.familyName ||= (state.name || "").split(" ").pop() || "Unknown";
  state.legacy.cumulativeScore ||= 0;
  state.legacy.milestones ||= [];
}
function milestoneToast(title, text) {
  let el = document.getElementById("verdant-milestone-toast");
  if (!el) {
    el = document.createElement("div");
    el.id = "verdant-milestone-toast";
    el.className = "verdant-milestone-toast";
    document.body.appendChild(el);
  }
  el.innerHTML = `<div class="m-title">${title}</div><div class="m-text">${text}</div>`;
  el.classList.add("show");
  clearTimeout(ledgerMilestoneTimer);
  ledgerMilestoneTimer = setTimeout(() => el.classList.remove("show"), 3200);
}
function awardMilestone(id, title, text, points = 25) {
  if (!state) return;
  ensureLegacyShape();
  if (state.legacy.milestones.includes(id)) return;
  state.legacy.milestones.push(id);
  state.legacy.cumulativeScore += points;
  addLog(`Milestone: ${text}`, { karma: Math.min(3, Math.max(0, Math.round(points / 25))) });
  milestoneToast(title, text);
}
function checkVerdantMilestones() {
  if (!state || !state.alive) return;
  ensureLegacyShape();
  const nw = legacyNetWorth();
  const children = Object.values(state.relationships || {}).filter(r => r.role === "Child").length;
  if (state.age >= 18) awardMilestone("adult", "Milestone", "You reached adulthood. The ledger is yours now.", 40);
  if (state.age >= 65) awardMilestone("elder", "Milestone", "You reached elderhood with stories behind you.", 75);
  if (state.job) awardMilestone("first_job", "Milestone", "You started a career path.", 35);
  if (state.education === "College" || state.flags?.hasDegree) awardMilestone("college_grad", "Milestone", "You earned a college degree.", 60);
  if (state.married) awardMilestone("married", "Milestone", "You built a marriage into your story.", 55);
  if (children > 0) awardMilestone("parent", "Milestone", "You became a parent. The next generation exists.", 70);
  if (nw >= 100000) awardMilestone("nw100k", "Milestone", "Your net worth crossed $100,000.", 50);
  if (nw >= 1000000) awardMilestone("nw1m", "Major Milestone", "Your net worth crossed $1,000,000.", 120);
  if ((state.stats?.karma || 0) >= 90) awardMilestone("karma90", "Milestone", "Your reputation became unusually honorable.", 50);
}
function renderLegacySummary() {
  ensureLegacyShape();
  const ms = state.legacy.milestones || [];
  return `<section class="panel legacy-panel">
    <div class="section-label">🌿 Legacy</div>
    <div class="row"><div><div class="row-title">Generation ${state.legacy.generation} of the ${state.legacy.familyName} line</div><div class="row-sub">A Verdant-style dynasty layer added to The Ledger.</div></div></div>
    <div class="legacy-chip-row">
      <span class="legacy-chip">Score ${ledgerLegacyScore()}</span>
      <span class="legacy-chip">Cumulative ${state.legacy.cumulativeScore || 0}</span>
      <span class="legacy-chip">Milestones ${ms.length}</span>
      <span class="legacy-chip">Net ${safeMoneyValue(legacyNetWorth())}</span>
    </div>
  </section>`;
}
function exportLedgerSave() {
  if (!state) return addToast("No active life to export.");
  ensureStateShape();
  ensureLegacyShape();
  const payload = {
    app: "The Ledger",
    upgraded_with: "Verdant-inspired safe upgrade pack",
    exported_at: new Date().toISOString(),
    active_slot: activeSlot,
    state
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `ledger-save-slot-${activeSlot}-${Date.now()}.json`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 0);
  milestoneToast("Save Exported", "A portable JSON copy of this life was created.");
}
function importLedgerSave() {
  let input = document.getElementById("ledger-import-input");
  if (!input) {
    input = document.createElement("input");
    input.id = "ledger-import-input";
    input.className = "file-input-hidden";
    input.type = "file";
    input.accept = ".json,application/json";
    document.body.appendChild(input);
  }
  input.onchange = () => {
    const file = input.files && input.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const parsed = JSON.parse(String(reader.result || "{}"));
        const imported = parsed.state || parsed;
        if (!imported || typeof imported !== "object" || !imported.name || !imported.stats || !Array.isArray(imported.log)) {
          throw new Error("This does not look like a Ledger save.");
        }
        state = imported;
        ensureStateShape();
        ensureLegacyShape();
        save();
        render();
        milestoneToast("Save Imported", "The imported life is now loaded in the active slot.");
      } catch (err) {
        alert("Import failed: " + (err.message || err));
      }
    };
    reader.readAsText(file);
    input.value = "";
  };
  input.click();
}
function continueAsHeir() {
  if (!state || state.alive) return;
  const old = state;
  const heir = Object.values(old.relationships || {}).find(r => r.role === "Child" && r.alive);
  if (!heir) return;
  const estate = Math.max(0, legacyNetWorth(old));
  const inheritance = Math.round(estate * .45);
  const oldScore = ledgerLegacyScore(old);
  const oldLegacy = old.legacy || {};
  const familyName = oldLegacy.familyName || (old.name || "").split(" ").pop() || "Legacy";
  const nextName = heir.name || randomName(chance(.5) ? "male" : "female").replace(/ \w+$/, ` ${familyName}`);
  newGame({
    name: nextName,
    gender: chance(.5) ? "male" : "female",
    background: old.background || "middle",
    city: old.city || pick(cities),
    startingMoney: inheritance,
    sandbox: old.sandbox || {},
    sandboxMode: !!old.sandboxMode
  });
  ensureLegacyShape();
  state.legacy.generation = (oldLegacy.generation || 1) + 1;
  state.legacy.familyName = familyName;
  state.legacy.cumulativeScore = (oldLegacy.cumulativeScore || 0) + oldScore;
  state.legacy.inheritedFrom = old.name;
  state.legacy.lastInheritance = inheritance;
  state.legacy.milestones = [];
  addLog(`You carry the ${familyName} legacy forward after inheriting ${safeMoneyValue(inheritance)} from ${old.name}.`);
  save();
  render();
  milestoneToast("Legacy Continued", `${nextName} begins generation ${state.legacy.generation}.`);
}

