function rand(lo, hi) { return Math.floor(Math.random() * (hi - lo + 1)) + lo; }
function pick(a) { return a[Math.floor(Math.random() * a.length)]; }
function chance(p) { return Math.random() < p; }
function clamp(n) { return Math.max(0, Math.min(100, Math.round(n))); }
function money(n) {
  if (n === 0) return "$0";
  const abs = Math.abs(n);
  const neg = n < 0 ? "-" : "";
  if (abs >= 1e9) return `${neg}$${(abs/1e9).toFixed(1).replace(/\.0$/, "")}B`;
  if (abs >= 1e6) return `${neg}$${(abs/1e6).toFixed(1).replace(/\.0$/, "")}M`;
  if (abs >= 10000) return `${neg}$${Math.round(abs/1000)}K`;
  return `${neg}$${abs.toLocaleString()}`;
}
function cap(s) { return s.charAt(0).toUpperCase() + s.slice(1).replace(/[A-Z]/g, m => " " + m); }

function randomName(gender) {
  return `${pick(names[gender])} ${pick(names.last)}`;
}

function makeParentFinances(bg) {
  const income = rand(bg.parentIncome?.[0] || 50000, bg.parentIncome?.[1] || 100000);
  const netWorth = rand(bg.parentNetWorth?.[0] || 10000, bg.parentNetWorth?.[1] || 120000);
  return {
    income,
    netWorth,
    liquid: Math.max(100, Math.round(Math.min(netWorth * .28, income * rand(3, 14) / 100))),
    givenThisYear: 0
  };
}

function iraYearRate() {
  if (chance(.12)) return -rand(1, 6) / 100;
  return rand(20, 70) / 1000;
}

function retirement401kYearRate() {
  return rand(35, 56) / 1000;
}

function newGame(opts = {}) {
  const gender = opts.gender || (chance(.5) ? "male" : "female");
  const bg = backgrounds.find(b => b.id === opts.background) || pick(backgrounds);
  const base = {
    health: rand(55, 85), happiness: rand(45, 80), smarts: rand(35, 75), looks: rand(35, 80),
    stress: rand(5, 35), karma: 50, popularity: rand(20, 60), discipline: rand(25, 65),
    creativity: rand(20, 70), athleticism: rand(20, 70), mentalHealth: rand(45, 85),
    confidence: rand(25, 75), energy: rand(35, 85)
  };
  Object.entries(bg.mods).forEach(([k, v]) => base[k] = clamp(base[k] + v));
  if (opts.customStats) {
    Object.entries(opts.customStats).forEach(([k, v]) => { if (k in base) base[k] = clamp(v); });
  }
  const name = opts.name || randomName(gender);
  const last = name.split(" ").pop();
  const sandboxFlags = {
    moneyMultiplier: 1, easyRelationships: false, perfectHealth: false, fertilityControl: false, fameBoost: false,
    ...(opts.sandbox || {})
  };
  state = {
    name, gender, age: 0, alive: true, cause: "", city: opts.city || pick(cities), background: bg.id,
    familyWealth: bg.wealth, allowance: bg.allowance || 0,
    parentFinances: makeParentFinances(bg),
    stats: base, money: opts.startingMoney !== undefined ? opts.startingMoney : bg.cash,
    savings: 0, debt: 0, ira: 0, retirement401k: 0, iraRate: .02, retirement401kRate: .035,
    education: "Preschool", job: null, traits: makeIntelligenceProfile(base, opts), school: {
      grade: 75,
      level: "None",
      clubs: [],
      subjectGrades: { math: rand(55, 82), english: rand(55, 82), science: rand(55, 82), history: rand(55, 82), arts: rand(55, 82) },
      absences: 0,
      conduct: 75,
      studyStreak: 0,
      track: "general",
      testScore: null,
      iqTests: [],
      iqRevealed: true,
      academicOffset: 0,
      choicePrompted: {},
      lastStageKey: "preschool",
      scholarshipAward: 0,
      honors: [],
      warnings: []
    },
    college: null, major: null,
    married: false, pregnant: false, familyPlan: "open", fame: 0, followers: 0, inventory: [], assets: [],
    home: "parents", car: null, rentals: [], clubs: [], actionsTaken: {},
    activityHabits: { lastYear: {}, currentYear: {}, streaks: {} },
    martialArts: { styles: {}, suspended: false },
    sandbox: sandboxFlags,
    sandboxMode: !!opts.sandboxMode,
    flags: {}, relationships: makeFamily(last), log: [], pending: null, achievements: [],
    legacy: { generation: 1, familyName: last, cumulativeScore: 0, milestones: [] }
  };
  addLog(`Born in ${state.city} to a ${bg.name.toLowerCase()}.`);
  addLog("A blank page entered the archive.");
  save();
}

function makeFamily(last) {
  const rels = {
    mother: { name: `${pick(["Diane","Mary","Linda","Patricia","Susan","Karen"])} ${last}`, role: "Mother", bond: rand(58, 92), trust: rand(50, 90), alive: true },
  };
  if (chance(.76)) rels.father = { name: `${pick(["Robert","William","Charles","Thomas","David","Frank"])} ${last}`, role: "Father", bond: rand(45, 88), trust: rand(45, 85), alive: true };
  for (let i = 0; i < rand(0, 2); i++) {
    const g = chance(.5) ? "male" : "female";
    rels[`sibling${i}`] = { name: randomName(g).replace(/ \w+$/, ` ${last}`), role: chance(.5) ? "Older Sibling" : "Younger Sibling", bond: rand(35, 82), trust: rand(35, 82), alive: true };
  }
  return rels;
}

function lifeStage() {
  if (state.age <= 4) return "Baby";
  if (state.age <= 12) return "Child";
  if (state.age <= 17) return "Teen";
  if (state.age <= 29) return "Young Adult";
  if (state.age <= 49) return "Adult";
  return "Senior";
}

function addLog(text, deltas = null) {
  state.log.unshift({ age: state.age, text, deltas: deltas ? deltaSummary(deltas) : [] });
}
function deltaSummary(d) {
  return Object.entries(d).filter(([,v]) => v !== 0).map(([k, v]) => ({
    text: k === "money" ? `${v > 0 ? "+" : ""}${money(v)}`
      : k === "ira" ? `IRA ${v > 0 ? "+" : ""}${money(v)}`
      : k === "retirement401k" ? `401k ${v > 0 ? "+" : ""}${money(v)}`
      : k === "debt" ? `Debt ${v > 0 ? "+" : ""}${money(v)}`
      : `${cap(k)} ${v > 0 ? "+" : ""}${v}`,
    cls: ["debt","stress"].includes(k) ? (v > 0 ? "down" : "up") : (v > 0 ? "up" : "down")
  }));
}
function applyDeltas(d) {
  Object.entries(d || {}).forEach(([k, v]) => {
    // Sandbox money multiplier is documented as boosting INFLOWS only, so it must
    // not also inflate costs (negative money deltas).
    if (k === "money") state.money += v > 0 ? Math.round(v * state.sandbox.moneyMultiplier) : Math.round(v);
    else if (k === "debt") state.debt += v;
    else if (k in state.stats) state.stats[k] = clamp(state.stats[k] + v);
    else if (k === "followers") state.followers = Math.max(0, state.followers + v);
    else if (k === "fame") state.fame = clamp(state.fame + v);
  });
  if (state.sandbox.perfectHealth) state.stats.health = 100;
  showStatDeltas(d);
}
// Additively merge yearly stat deltas (focus + lifestyle + budget can touch the same
// stat). Object.assign would overwrite shared keys; this sums them so effects stack.
function mergeAddDeltas(target, src) {
  Object.entries(src || {}).forEach(([k, v]) => { target[k] = (target[k] || 0) + v; });
  return target;
}
function mergeDeltas(target, src) {
  return mergeAddDeltas(target || {}, src || {});
}
function normalizeChoiceOutcome(rawDeltas, rawLog, rawAfter) {
  if (typeof rawDeltas === "function") {
    const outcome = rawDeltas(state);
    if (outcome == null) return null;
    if (outcome && typeof outcome === "object" && ("deltas" in outcome || "log" in outcome || "after" in outcome)) {
      return { deltas: outcome.deltas || {}, log: outcome.log || rawLog, after: outcome.after || rawAfter };
    }
    return { deltas: outcome || {}, log: rawLog, after: rawAfter };
  }
  return { deltas: rawDeltas || {}, log: rawLog, after: rawAfter };
}

