    <div class="row"><div><div class="row-title">IRA Actions</div></div><div class="mini-actions"><button class="icon-btn" onclick="contributeIRA(5000)" ${state.money < 5000 ? "disabled" : ""}>+$5K</button><button class="icon-btn" onclick="contributeIRA('paycheck')" ${!state.job || state.money < paycheck ? "disabled" : ""}>+Paycheck</button><button class="icon-btn" onclick="contributeIRA('all')" ${state.money <= 0 ? "disabled" : ""}>+All</button><button class="icon-btn" onclick="withdrawIRA(5000)" ${state.ira < 5000 ? "disabled" : ""}>Take $5K</button><button class="icon-btn" onclick="withdrawIRA('all')" ${state.ira <= 0 ? "disabled" : ""}>Take All</button></div></div>
