function renderEvent() {
  const ev = state.pending;
  const text = typeof ev.text === "function" ? ev.text(state) : ev.text;
  if (ev.schoolSelect) return renderSchoolSelectionEvent(ev, text);
  if (ev.combat) return renderCombatEvent(ev, text);
  if (ev.college) return renderCollegeEvent(ev, text);
  return `<section class="event-card"><div class="event-title mono">An Event</div><div class="event-text">${text}</div><div class="choices">${ev.choices.map((c,i) => `<button class="choice" onclick="choose(${i})">${c[0]}</button>`).join("")}</div></section>`;
}


function renderSchoolSelectionEvent(ev, text) {
  const key = ev.stage || schoolStageKey();
  const opts = schoolTypeOptions.filter(o => o.stages.includes(key));
  const cards = opts.map(opt => {
    const allowed = !opt.req || opt.req(state);
    const costText = opt.cost ? `${money(opt.cost)}/yr` : "Free";
    const mods = Object.entries(opt.mods || {}).map(([k,v]) => `${cap(k)} ${v > 0 ? "+" : ""}${v}`).join(" · ") || "Balanced";
    let reason = "";
    if (!allowed) {
      if (opt.cost && !canFundSchoolCost(opt.cost)) reason = "Funding not available";
      else reason = "Grades, IQ, or requirements not met";
    }
    return `<button class="school-option-card ${!allowed ? "disabled" : ""}" onclick="${allowed ? `selectSchoolFromEvent('${opt.id}')` : ""}">
      <div class="school-option-top"><div><div class="ico">${opt.icon}</div><div class="ttl">${opt.name}</div><div class="desc">${opt.desc}</div></div><span class="school-badge ${allowed ? "good" : "bad"}">${costText}</span></div>
      <div class="school-badge-row"><span class="school-badge">${opt.category}</span><span class="school-badge">${mods}</span>${effectiveIQ() >= 125 ? `<span class="school-badge good">IQ ${effectiveIQ()}</span>` : ""}${calcGPA() >= 3.5 ? `<span class="school-badge good">GPA ${calcGPA().toFixed(2)}</span>` : ""}</div>
      ${reason ? `<div class="locked-reason">${reason}</div>` : ""}
    </button>`;
  }).join("");
  return `<section class="event-card school-choice-event"><div class="event-title mono">School Placement</div><div class="event-text">${text}</div>
    <div class="school-choice-note">This is now a full-page decision. Your grades, IQ, family money, and current discipline can open or lock school options.</div>
    <div class="school-card-list">${cards}</div>
  </section>`;
}

function renderCollegeEvent(ev, text) {
  const schools = eligibleCollegeSchools();
  const pairCards = schools.map(s => {
    const topMajors = collegeMajors.slice(0, 10).map(m => {
      const preview = collegeOutcomePreview(s, m);
      return `<button class="choice" onclick="enrollCollegeChoice('${s.id}','${m.id}')"><strong>${m.name}</strong><br><span class="mono">${m.school} · ${preview}</span></button>`;
    }).join("");
    return `<div class="school-option-card">
      <div class="school-option-top"><div><div class="ico">🎓</div><div class="ttl">${s.name}</div><div class="desc">${s.tier} · ${s.desc}</div></div><span class="school-badge good">${scholarshipCoverageForSchool(s) >= s.cost ? "FREE" : money(Math.max(0, s.cost - scholarshipCoverageForSchool(s))) + "/yr"}</span></div>
      <div class="school-badge-row"><span class="school-badge">Min GPA ${s.minGpa.toFixed(2)}</span><span class="school-badge">Quality ×${s.quality.toFixed(2)}</span>${scholarshipCoverageForSchool(s) ? `<span class="school-badge good">Aid ${money(scholarshipCoverageForSchool(s))}/yr</span>` : ""}</div>
      <div class="college-major-pair">${topMajors}</div>
    </div>`;
  }).join("");
  return `<section class="event-card"><div class="event-title mono">College Decision</div><div class="event-text">${text}</div>
    <div class="school-card-list">${pairCards || `<div class="row"><div><div class="row-title">No college admits yet</div><div class="row-sub">Your GPA is too low right now. Trade, certificate, or work may be the better route.</div></div></div>`}</div>
    <div class="choices" style="margin-top:10px">${ev.choices.map((c,i) => `<button class="choice" onclick="choose(${i})">${c[0]}</button>`).join("")}</div>
  </section>`;
}

function collegeOutcomePreview(school, major) {
  const parts = [];
  if (major.smarts) parts.push(`Smarts +${Math.round((major.smarts || 0) * school.quality)}`);
  if (major.creativity) parts.push(`Creativity +${Math.round((major.creativity || 0) * school.quality)}`);
  if (major.confidence) parts.push(`Confidence +${Math.round((major.confidence || 0) * school.quality)}`);
  if (major.stress) parts.push(`Stress +${major.stress}`);
  return parts.slice(0, 3).join(" · ") || "Balanced degree path";
}

function renderCombatEvent(ev, text) {
  const moves = getKnownMoves();
  const moveButtons = moves.length
    ? moves.map(({ style, move, progress }) => `<button class="choice" onclick="useFightMove('${style.id}','${move.id}')">${style.name}: ${move.name} <span class="mono">${martialRankName(style.id, progress.rank)}</span></button>`).join("")
    : `<button class="choice" onclick="useFightMove('random','')">Swing wildly</button>`;
  return `<section class="event-card"><div class="event-title mono">Fight</div><div class="event-text">${text}</div><div class="choices">
    ${moveButtons}
    ${moves.length ? `<button class="choice" onclick="useFightMove('random','')">Random trained move</button>` : ""}
    ${ev.choices.map((c,i) => `<button class="choice" onclick="choose(${i})">${c[0]}</button>`).join("")}
  </div></section>`;
}
function runPostRenderScroll() {
  const target = scrollAfterRender;
  scrollAfterRender = null;
  // Always auto-scroll the life log to bottom so newest is visible
  requestAnimationFrame(() => {
    const log = $("#life-log");
    if (log) log.scrollTop = log.scrollHeight;
    if (target === "event") {
      const eventCard = $(".event-card");
      if (eventCard) eventCard.scrollIntoView({ behavior: "smooth", block: "center" });
    }
  });
}
