function renderSplash() {
  // Pick a random tip to start with
  const firstTip = pick(LEDGER_TIPS);
  $("#app").innerHTML = `
    <div class="splash" id="splash-root">
      <div class="splash-version">v0.9 — IQ + Scholarships</div>

      <div class="splash-brand">The<span class="amp"> &</span> Ledger</div>
      <div class="splash-tagline">A Life, Recorded</div>

      <div class="splash-loader"><div class="splash-loader-bar" id="splash-loader"></div></div>
      <div class="splash-status" id="splash-status">Preparing the archive…</div>

      <div class="splash-tip">
        <div class="splash-tip-label">— A Note Before You Begin —</div>
        <div class="splash-tip-text" id="splash-tip">${firstTip}</div>
      </div>

      <button class="splash-enter" id="splash-enter" onclick="enterFromSplash()" style="opacity:0;pointer-events:none">Enter</button>
    </div>
  `;
  startSplashAnimation();
}

function startSplashAnimation() {
  // Clear any previous timers
  splashTimers.forEach(t => clearInterval(t) || clearTimeout(t));
  splashTimers = [];

  const phases = [
    { pct: 25, msg: "Setting the type…" },
    { pct: 50, msg: "Binding the spine…" },
    { pct: 75, msg: "Indexing past lives…" },
    { pct: 100, msg: "Ready when you are." }
  ];
  let i = 0;
  const advance = () => {
    if (i >= phases.length) return;
    const p = phases[i++];
    const bar = document.getElementById("splash-loader");
    const status = document.getElementById("splash-status");
    if (bar) bar.style.width = p.pct + "%";
    if (status) status.textContent = p.msg;
    if (i === phases.length) {
      // Reveal Enter button
      setTimeout(() => {
        const btn = document.getElementById("splash-enter");
        if (btn) {
          btn.style.transition = "opacity .5s ease";
          btn.style.opacity = "1";
          btn.style.pointerEvents = "auto";
        }
      }, 300);
    }
  };
  advance();
  splashTimers.push(setTimeout(advance, 600));
  splashTimers.push(setTimeout(advance, 1300));
  splashTimers.push(setTimeout(advance, 2100));

  // Rotate tips every 4 seconds
  let tipIdx = LEDGER_TIPS.indexOf(document.getElementById("splash-tip")?.textContent) || 0;
  splashTimers.push(setInterval(() => {
    const el = document.getElementById("splash-tip");
    if (!el) return;
    el.style.opacity = "0";
    setTimeout(() => {
      tipIdx = (tipIdx + 1) % LEDGER_TIPS.length;
      el.textContent = LEDGER_TIPS[tipIdx];
      el.style.opacity = "1";
    }, 300);
  }, 4000));
}

function enterFromSplash() {
  splashTimers.forEach(t => { clearInterval(t); clearTimeout(t); });
  splashTimers = [];
  const root = document.getElementById("splash-root");
  if (root) {
    root.classList.add("fading");
    setTimeout(() => {
      splashShown = true;
      render();
    }, 450);
  } else {
    splashShown = true;
    render();
  }
}

