const lifeGoalCatalog = [
  { id: "bestfriend", minAge: 6, maxAge: 100, name: "Build a close bond", desc: "Invest in people and create a meaningful relationship.", stat: "karma", reward: { happiness: 8, karma: 5, stress: -4 } },
  { id: "honorroll", minAge: 8, maxAge: 18, name: "Make the honor roll", desc: "Study hard and keep your GPA high.", stat: "smarts", require: s => calcGPA() >= 3.2, reward: { smarts: 4, discipline: 4, confidence: 4 } },
  { id: "varsity", minAge: 12, maxAge: 22, name: "Become a serious athlete", desc: "Train, play sports, and chase a scholarship.", stat: "athleticism", reward: { athleticism: 5, confidence: 5, health: 3 } },
  { id: "firsthome", minAge: 18, maxAge: 100, name: "Get your own place", desc: "Move out, rent, or buy property.", stat: "discipline", require: s => s.home && s.home !== "parents", reward: { happiness: 7, confidence: 4 } },
  { id: "debtfree", minAge: 18, maxAge: 100, name: "Become debt free", desc: "Pay off all debt and stabilize your money.", stat: "discipline", require: s => (s.debt || 0) <= 0 && (s.finance?.creditCardDebt || 0) <= 0, reward: { happiness: 8, stress: -8, discipline: 3 } },
  { id: "networth100k", minAge: 18, maxAge: 100, name: "Reach $100K net worth", desc: "Save, invest, work, and build assets.", stat: "discipline", require: s => legacyNetWorth(s) >= 100000, reward: { confidence: 7, happiness: 5 } },
  { id: "worldtraveler", minAge: 18, maxAge: 100, name: "Collect life experiences", desc: "Travel, make memories, and avoid living only for work.", stat: "happiness", reward: { happiness: 10, creativity: 3, stress: -5 } }
];

function financeNetWorth(s = state) {
  return legacyNetWorth(s) + Math.round(s.finance?.brokerage || 0) - Math.round(s.finance?.creditCardDebt || 0);
}
function creditScoreBand(score) {
  if (score >= 780) return { label: "Excellent", cls: "good" };
  if (score >= 700) return { label: "Good", cls: "good" };
  if (score >= 630) return { label: "Fair", cls: "money" };
  if (score >= 560) return { label: "Poor", cls: "bad" };
  return { label: "Damaged", cls: "bad" };
}
function emergencyMonths() {
  const style = lifestyleCatalog.find(x => x.id === state.life?.lifestyle) || lifestyleCatalog[1];
  const home = homes.find(h => h.id === state.home);
  const annual = Math.max(1, (style.cost || 0) + (home?.annualCost || 0) + (cars.find(c => c.id === state.car)?.annualCost || 0));
  return Math.floor(((state.savings || 0) / (annual / 12)) * 10) / 10;
}
function availableLifeGoals() {
  ensureStateShape();
  return lifeGoalCatalog.filter(g => state.age >= g.minAge && state.age <= g.maxAge && !(state.life.completedGoals || []).includes(g.id));
}
function ensureLifeFinanceShape() {
  if (!state) return;
  state.life ||= {};
  state.life.focus ||= "balanced";
  state.life.lifestyle ||= state.age < 18 ? "modest" : "modest";
  state.life.activeGoal ||= null;
  state.life.goalProgress ||= {};
  state.life.completedGoals ||= [];
  state.life.memories ||= [];
  state.life.lastYearSummary ||= "";
  state.finance ||= {};
  state.finance.budget ||= "balanced";
  state.finance.creditScore ??= Math.max(520, Math.min(820, 650 + Math.round((state.stats.discipline - 50) * 1.2) + (state.familyWealth === "wealthy" ? 35 : state.familyWealth === "low" ? -25 : 0)));
  state.finance.brokerage ||= 0;
  state.finance.brokerageRisk ||= "balanced";
  state.finance.creditCardDebt ||= 0;
  state.finance.insurance ??= false;
  state.finance.lastCashFlow ||= 0;
  state.finance.lastInvestmentReturn ||= 0;
  state.finance.lastYearTaxes ||= 0;
  state.finance.yearsLate ||= 0;
}

const __ledgerBaseEnsureStateShapeLifeFinance = ensureStateShape;
ensureStateShape = function() {
  __ledgerBaseEnsureStateShapeLifeFinance();
  ensureLifeFinanceShape();
};

function addLifeMemory(text) {
  ensureStateShape();
  state.life.memories.unshift({ age: state.age, text });
  state.life.memories = state.life.memories.slice(0, 10);
}

function setLifeFocus(id) {
  ensureStateShape();
  if (!lifeFocusCatalog.find(f => f.id === id)) return;
  state.life.focus = id;
  addLifeMemory(`You decided to focus this chapter on ${lifeFocusCatalog.find(f => f.id === id).name.toLowerCase()}.`);
  addLog(`Life focus changed to ${lifeFocusCatalog.find(f => f.id === id).name}.`);
  save(); render();
}
function setLifestyle(id) {
  ensureStateShape();
  if (!lifestyleCatalog.find(x => x.id === id)) return;
  state.life.lifestyle = id;
  addLog(`Lifestyle set to ${lifestyleCatalog.find(x => x.id === id).name}.`);
  save(); render();
}
function chooseLifeGoal(id) {
  ensureStateShape();
  const goal = availableLifeGoals().find(g => g.id === id);
  if (!goal) return addToast("That goal is not available right now.");
  state.life.activeGoal = id;
  state.life.goalProgress[id] ||= 0;
  addLifeMemory(`You chose a new personal goal: ${goal.name}.`);
  addLog(`New life goal: ${goal.name}.`);
  save(); render();
}
function pursueLifeGoal() {
  ensureStateShape();
  const goal = lifeGoalCatalog.find(g => g.id === state.life.activeGoal);
  if (!goal) return addToast("Choose a life goal first.");
  const key = `goal_${goal.id}`;
  if (state.actionsTaken[key]) return addToast("You already worked on that goal this year.");
  const statVal = state.stats[goal.stat] || 50;
  let gain = rand(10, 22) + Math.floor((statVal - 50) / 12);
  if (goal.require && goal.require(state)) gain += 35;
  state.life.goalProgress[goal.id] = Math.min(100, (state.life.goalProgress[goal.id] || 0) + Math.max(5, gain));
  state.actionsTaken[key] = true;
  const deltas = { discipline: 1, happiness: 1, stress: goal.id === "networth100k" || goal.id === "debtfree" ? 1 : -1 };
  applyDeltas(deltas);
  if (state.life.goalProgress[goal.id] >= 100) {
    completeLifeGoal(goal.id);
  } else {
    addLog(`You worked toward your goal: ${goal.name}. Progress is now ${state.life.goalProgress[goal.id]}%.`, deltas);
  }
  save(); render();
}
function completeLifeGoal(id) {
  ensureStateShape();
  const goal = lifeGoalCatalog.find(g => g.id === id);
  if (!goal || state.life.completedGoals.includes(id)) return;
  state.life.completedGoals.push(id);
  state.life.goalProgress[id] = 100;
  if (state.life.activeGoal === id) state.life.activeGoal = null;
  applyDeltas(goal.reward || {});
  addLifeMemory(`Completed goal: ${goal.name}.`);
  awardMilestone(`lifegoal_${id}`, "Life Goal Complete", goal.name, 45);
  addLog(`You completed a life goal: ${goal.name}.`, goal.reward || {});
}

function setBudgetStyle(id) {
  ensureStateShape();
  if (!budgetCatalog.find(b => b.id === id)) return;
  state.finance.budget = id;
  addLog(`Budget style changed to ${budgetCatalog.find(b => b.id === id).name}.`);
  save(); render();
}
function setBrokerageRisk(id) {
  ensureStateShape();
  if (!riskCatalog[id]) return;
  state.finance.brokerageRisk = id;
  addLog(`Brokerage risk set to ${riskCatalog[id].name}.`);
  save(); render();
}
function investBrokerage(amount) {
  ensureStateShape();
  let amt = amount === "all" ? state.money : Number(amount);
  amt = Math.max(0, Math.min(state.money, Math.round(amt || 0)));
  if (!amt) return addToast("No cash available to invest.");
  state.money -= amt;
  state.finance.brokerage += amt;
  addLog(`Invested ${money(amt)} into your brokerage account.`, { money: -amt, brokerage: amt });
  save(); render();
}
function withdrawBrokerage(amount) {
  ensureStateShape();
  let amt = amount === "all" ? state.finance.brokerage : Number(amount);
  amt = Math.max(0, Math.min(state.finance.brokerage, Math.round(amt || 0)));
  if (!amt) return addToast("No brokerage balance to withdraw.");
  state.finance.brokerage -= amt;
  state.money += amt;
  addLog(`Withdrew ${money(amt)} from brokerage.`, { money: amt, brokerage: -amt });
  save(); render();
}
// Single source of truth for the unsecured credit-card limit.
// Every credit-limit display + the enforcing useCreditCard route through this.
function ledgerCreditLimit(score, reserves) {
  if (score == null) score = (state && state.finance && state.finance.creditScore) || 650;
  score = Math.round(Number(score) || 650);
  if (score >= 780) return 50000;
  if (score >= 720) return 25000;
  if (score >= 680) return 12000;
  if (score >= 620) return 5000;
  return 1000;
}
window.ledgerCreditLimit = ledgerCreditLimit;

function useCreditCard(amount, reason = "spending") {
  ensureStateShape();
  if (state.age < 18) return addToast("Credit cards unlock at 18.");
  const score = state.finance.creditScore || 650;
  const limit = ledgerCreditLimit(score);
  const amt = Math.round(Number(amount) || 0);
  if (!amt || state.finance.creditCardDebt + amt > limit) return addToast(`Credit limit is about ${money(limit)}.`);
  state.finance.creditCardDebt += amt;
  state.money += amt;
  state.finance.creditScore = Math.max(300, state.finance.creditScore - Math.ceil(amt / 1200));
  addLog(`Used credit for ${reason}: ${money(amt)} added to cash, but your card balance increased.`, { money: amt, creditCardDebt: amt });
  save(); render();
}
function payCreditCard(amount) {
  ensureStateShape();
  let amt = amount === "all" ? Math.min(state.money, state.finance.creditCardDebt) : Number(amount);
  amt = Math.max(0, Math.min(state.money, state.finance.creditCardDebt, Math.round(amt || 0)));
  if (!amt) return addToast("No payment available.");
  state.money -= amt;
  state.finance.creditCardDebt -= amt;
  state.finance.creditScore = Math.min(850, state.finance.creditScore + Math.ceil(amt / 800));
  addLog(`Paid ${money(amt)} toward your credit card.`, { money: -amt, creditCardDebt: -amt });
  save(); render();
}
function buyInsurance() {
  ensureStateShape();
  if (state.age < 18) return addToast("Insurance unlocks at 18.");
  if (state.finance.insurance) return addToast("You already have insurance.");
  const cost = 1200;
  if (state.money < cost) return addToast("Not enough cash for the first insurance premium.");
  state.money -= cost;
  state.finance.insurance = true;
  addLog("You bought basic health insurance. Hospital debt risk is lower now.", { money: -cost, stress: -2 });
  applyDeltas({ stress: -2 });
  save(); render();
}

function resolveLifeAndFinanceYear() {
  if (!state || !state.alive) return;
  ensureStateShape();
  let cashFlow = 0;
  let deltas = {};
  const focus = lifeFocusCatalog.find(f => f.id === state.life.focus) || lifeFocusCatalog[0];
  const lifestyle = lifestyleCatalog.find(x => x.id === state.life.lifestyle) || lifestyleCatalog[1];
  const budget = budgetCatalog.find(b => b.id === state.finance.budget) || budgetCatalog[1];

  if (state.age >= 13) {
    deltas = mergeAddDeltas(deltas, focus.yearly);
  }
  if (state.age >= 18) {
    const lifestyleCost = Math.round(lifestyle.cost || 0);
    state.money -= lifestyleCost;
    cashFlow -= lifestyleCost;
    deltas = mergeAddDeltas(deltas, lifestyle.deltas);
    if (lifestyleCost) addLog(`${lifestyle.name} lifestyle cost ${money(lifestyleCost)} this year.`, { money: -lifestyleCost });
  }

  if (state.age >= 18 && state.job) {
    const salary = state.job.salary || 0;
    const taxRate = salary > 180000 ? .28 : salary > 90000 ? .22 : salary > 45000 ? .16 : .10;
    const taxes = Math.round(salary * taxRate);
    state.money -= taxes;
    state.finance.lastYearTaxes = taxes;
    cashFlow -= taxes;
    addLog(`Taxes withheld for the year: ${money(taxes)}.`, { money: -taxes });

    const autoSave = Math.min(state.money, Math.max(0, Math.round(salary * budget.autoSave)));
    if (autoSave > 0) {
      state.money -= autoSave;
      state.savings += autoSave;
      cashFlow -= autoSave;
      addLog(`${budget.name}: auto-saved ${money(autoSave)}.`, { money: -autoSave });
    }
    const autoInvest = Math.min(state.money, Math.max(0, Math.round(salary * budget.autoInvest)));
    if (autoInvest > 0) {
      state.money -= autoInvest;
      state.finance.brokerage += autoInvest;
      cashFlow -= autoInvest;
      addLog(`${budget.name}: auto-invested ${money(autoInvest)}.`, { money: -autoInvest });
    }
    deltas = mergeAddDeltas(deltas, budget.deltas);
  }

  if (state.finance.brokerage > 0) {
    const risk = riskCatalog[state.finance.brokerageRisk] || riskCatalog.balanced;
    const pct = rand(risk.min, risk.max) / 100;
    const change = Math.round(state.finance.brokerage * pct);
    state.finance.brokerage = Math.max(0, state.finance.brokerage + change);
    state.finance.lastInvestmentReturn = change;
    addLog(`Brokerage returned ${(pct * 100).toFixed(1)}% this year.`, { brokerage: change });
  }

  if (state.finance.creditCardDebt > 0) {
    const interest = Math.max(15, Math.round(state.finance.creditCardDebt * .19));
    state.finance.creditCardDebt += interest;
    state.finance.creditScore = Math.max(300, state.finance.creditScore - (state.money < 0 ? 18 : 6));
    addLog(`Credit card interest added ${money(interest)}. Carrying balances hurts your credit.`, { creditCardDebt: interest });
  } else if (state.age >= 18) {
    state.finance.creditScore = Math.min(850, state.finance.creditScore + 3 + (state.savings > 0 ? 2 : 0));
  }

  if (state.finance.insurance && state.age >= 18) {
    const premium = 1200;
    state.money -= premium;
    cashFlow -= premium;
    addLog(`Insurance premium paid: ${money(premium)}.`, { money: -premium });
  }

  const active = lifeGoalCatalog.find(g => g.id === state.life.activeGoal);
  if (active && !state.actionsTaken[`goal_${active.id}`]) {
    const passive = Math.max(1, Math.floor(((state.stats[active.stat] || 50) - 35) / 15));
    state.life.goalProgress[active.id] = Math.min(100, (state.life.goalProgress[active.id] || 0) + passive);
    if (state.life.goalProgress[active.id] >= 100) completeLifeGoal(active.id);
  }

  state.finance.lastCashFlow = cashFlow;
  if (Object.keys(deltas).length) applyDeltas(deltas);
  if (chance(.22) && state.age >= 10) {
    const memory = pick([
      "A small ordinary day stuck in your memory.",
      "You realized your routine is quietly shaping who you are.",
      "A conversation, a bill, and a private thought all landed in the same week.",
      "The year had no headline, but it had a mood."
    ]);
    addLifeMemory(memory);
  }
}

const __ledgerBaseAgeUpLifeFinance = ageUp;
ageUp = function() {
  if (state && state.alive && !state.pending) resolveLifeAndFinanceYear();
  return __ledgerBaseAgeUpLifeFinance.apply(this, arguments);
};

const __ledgerBaseGetVisibleHubsLifeFinance = getVisibleHubs;
getVisibleHubs = function() {
  const hubs = __ledgerBaseGetVisibleHubsLifeFinance();
  return hubs.map(h => h.id === "life" ? { id: "lifehub", icon: "📖", label: "Life" } : h);
};

const __ledgerBaseRenderHubContentLifeFinance = renderHubContent;
renderHubContent = function(hubId) {
  if (hubId === "lifehub") return renderLifeHub();
  return __ledgerBaseRenderHubContentLifeFinance(hubId);
};

function renderLifeHub() {
  ensureStateShape();
  const focus = lifeFocusCatalog.find(f => f.id === state.life.focus) || lifeFocusCatalog[0];
  const lifestyle = lifestyleCatalog.find(x => x.id === state.life.lifestyle) || lifestyleCatalog[1];
  const activeGoal = lifeGoalCatalog.find(g => g.id === state.life.activeGoal);
  const memories = state.life.memories || [];
  const goals = availableLifeGoals();
  return `<div class="life-dashboard">
    <section class="panel">
      <div class="section-label">📖 Life Chapter</div>
      <div class="row"><div><div class="row-title">${lifeStage()} chapter</div><div class="row-sub">Current focus: ${focus.icon} ${focus.name} - Lifestyle: ${lifestyle.name}</div></div></div>
      <div class="lf-pill-row">
        <span class="lf-pill">Age ${state.age}</span>
        <span class="lf-pill good">${state.life.completedGoals.length} goals complete</span>
        <span class="lf-pill money">Net ${money(financeNetWorth())}</span>
        <span class="lf-pill ${state.stats.stress > 75 ? "bad" : "good"}">Stress ${state.stats.stress}</span>
      </div>
    </section>
    <section class="panel">
      <div class="section-label">🌟 Choose Your Life Focus</div>
      <div class="lf-grid">${lifeFocusCatalog.map(f => `<button class="lf-card ${state.life.focus === f.id ? "selected" : ""}" onclick="setLifeFocus('${f.id}')"><div class="lf-title">${f.icon} ${f.name}</div><div class="lf-sub">${f.desc}</div></button>`).join("")}</div>
    </section>
    <section class="panel">
      <div class="section-label">🏙️ Lifestyle</div>
      <div class="lf-grid">${lifestyleCatalog.map(l => `<button class="lf-card ${state.life.lifestyle === l.id ? "selected" : ""}" onclick="setLifestyle('${l.id}')"><div class="lf-title">${l.name}</div><div class="lf-sub">${state.age < 18 ? "Family lifestyle influence" : money(l.cost) + "/yr"} - ${l.desc}</div></button>`).join("")}</div>
    </section>
    <section class="panel">
      <div class="section-label">🎯 Personal Goal</div>
      ${activeGoal ? `<div class="lf-card selected"><div class="lf-title">${activeGoal.name}</div><div class="lf-sub">${activeGoal.desc}</div><div class="life-goal-meter"><span style="width:${state.life.goalProgress[activeGoal.id] || 0}%"></span></div><div class="lf-pill-row"><span class="lf-pill good">${state.life.goalProgress[activeGoal.id] || 0}% complete</span></div><div class="mini-actions" style="margin-top:10px"><button class="icon-btn" onclick="pursueLifeGoal()" ${state.actionsTaken[`goal_${activeGoal.id}`] ? "disabled" : ""}>Work on goal</button></div></div>` : `<div class="row"><div><div class="row-title">No active personal goal</div><div class="row-sub">Pick one. It gives the life sim direction between age-ups.</div></div></div>`}
      <div class="lf-grid" style="margin-top:9px">${goals.slice(0, 6).map(g => `<button class="lf-card" onclick="chooseLifeGoal('${g.id}')"><div class="lf-title">${g.name}</div><div class="lf-sub">${g.desc}</div></button>`).join("")}</div>
    </section>
    <section class="panel">
      <div class="section-label">📝 Memories</div>
      ${memories.length ? memories.map(m => `<div class="life-memory"><b>Age ${m.age}:</b> ${m.text}</div>`).join("") : `<div class="row"><div><div class="row-title">No memories yet</div><div class="row-sub">Big decisions and quiet years will start filling this in.</div></div></div>`}
    </section>
  </div>`;
}

