    <div class="row"><div><div class="row-title">Deposit</div></div><div class="mini-actions"><button class="icon-btn" onclick="depositSavings(5000)" ${state.money < 5000 ? "disabled" : ""}>+$5K</button><button class="icon-btn" onclick="depositSavings('paycheck')" ${!state.job || state.money < paycheck ? "disabled" : ""}>+Paycheck</button><button class="icon-btn" onclick="depositSavings('all')" ${state.money <= 0 ? "disabled" : ""}>+All</button></div></div>
