    <div class="row"><div><div class="row-title">Risk</div></div><div class="mini-actions">${Object.keys(riskCatalog).map(k => `<button class="icon-btn" onclick="setBrokerageRisk('${k}')" ${state.finance.brokerageRisk === k ? "disabled" : ""}>${riskCatalog[k].name}</button>`).join("")}</div></div>
