// ========== FINANCE VISUAL + BANKING SYSTEM UPGRADE ==========
const wealthHealthInsurancePlans = [
  { id: "none", name: "No Insurance", coverage: 0, premium: 0, deductible: 0, desc: "You pay the full bill. Cheap now, brutal during emergencies." },
  { id: "basic50", name: "Basic 50% Plan", coverage: .50, premium: 1200, deductible: 1200, desc: "Affordable starter coverage. Good enough for small emergencies." },
  { id: "premium90", name: "Premium 90% Plan", coverage: .90, premium: 6000, deductible: 500, desc: "Expensive, but most hospital bills are handled." },
  { id: "elite100", name: "Elite 100% Plan", coverage: 1.00, premium: 18000, deductible: 0, desc: "Almost unfair. If you can afford it, care feels free." }
];

const entrepreneurshipCatalog = [
  { id: "lawncare", name: "Lawn Care Hustle", minAge: 12, startup: 150, yearlyMin: 500, yearlyMax: 2500, scaleStat: "discipline", failureRisk: .06, desc: "Neighborhood work. Low cost, honest cash, builds discipline." },
  { id: "resale", name: "Sneaker / Resale Shop", minAge: 14, startup: 500, yearlyMin: -150, yearlyMax: 6500, scaleStat: "smarts", failureRisk: .09, desc: "Flip goods online. Can grow fast, but inventory mistakes hurt." },
  { id: "content", name: "Content Channel", minAge: 13, startup: 200, yearlyMin: 0, yearlyMax: 5500, scaleStat: "creativity", failureRisk: .07, desc: "Slow at first. Popularity and creativity can turn into income." },
  { id: "tutoringbiz", name: "Tutoring Side Business", minAge: 15, startup: 75, yearlyMin: 800, yearlyMax: 7500, scaleStat: "smarts", failureRisk: .05, desc: "Use strong grades to make money helping others." },
  { id: "contracting", name: "Small Contracting Company", minAge: 18, startup: 7000, yearlyMin: -3000, yearlyMax: 65000, scaleStat: "discipline", failureRisk: .10, desc: "Real overhead, real upside. Better with high discipline." },
  { id: "startup", name: "Tech Startup", minAge: 18, startup: 15000, yearlyMin: -12000, yearlyMax: 220000, scaleStat: "iq", failureRisk: .14, desc: "High risk. High IQ, smarts, and luck can create a huge exit." }
];

function selectedHealthInsurancePlan() {
  ensureStateShape();
  const raw = state.finance && state.finance.insurance;
  const id = raw === true ? "basic50" : (raw || "none");
  return wealthHealthInsurancePlans.find(p => p.id === id) || wealthHealthInsurancePlans[0];
}

function normalizeAdvancedFinanceShape() {
  if (!state) return;
  state.finance ||= {};
  if (state.finance.insurance === true) state.finance.insurance = "basic50";
  if (state.finance.insurance === false || state.finance.insurance == null) state.finance.insurance = "none";
  state.finance.assetBackedLoan ||= 0;
  state.finance.assetBackedLoanRate ||= .07;
  state.finance.trustFunds ||= {};
  state.finance.businesses ||= [];
  state.finance.nilDeals ||= 0;
  state.finance.lastBusinessIncome ||= 0;
  state.finance.lastLoanInterest ||= 0;
  state.finance.wealthLineHistory ||= [];
  state.finance.brokerageOpened ??= (state.finance.brokerage || 0) > 0;
  // Keep trust accounts aligned with current children.
  Object.entries(state.relationships || {}).forEach(([key, r]) => {
    if (r && r.role === "Child") state.finance.trustFunds[key] ??= 0;
  });
}

const __ledgerEnsureStateBeforeFinanceVisual = ensureStateShape;
ensureStateShape = function() {
  __ledgerEnsureStateBeforeFinanceVisual();
  normalizeAdvancedFinanceShape();
};

function advancedFinanceNetWorth(s = state) {
  const base = legacyNetWorth(s);
  const f = s.finance || {};
  const trusts = Object.values(f.trustFunds || {}).reduce((a, b) => a + Math.round(Number(b) || 0), 0);
  const businesses = (f.businesses || []).reduce((a, b) => a + Math.max(0, Math.round(Number(b.value) || 0)), 0);
  return Math.round(base + (f.brokerage || 0) + trusts + businesses - (f.creditCardDebt || 0) - (f.assetBackedLoan || 0));
}
financeNetWorth = function(s = state) { return advancedFinanceNetWorth(s); };

function availableCollateral() {
  ensureStateShape();
  const savingsCollateral = Math.round((state.savings || 0) * .80);
  const brokerageCollateral = Math.round((state.finance.brokerage || 0) * .60);
  const iraCollateral = Math.round((state.ira || 0) * .25);
  return Math.max(0, savingsCollateral + brokerageCollateral + iraCollateral - (state.finance.assetBackedLoan || 0));
}

function setHealthInsurance(planId) {
  ensureStateShape();
  if (state.age < 18) return addToast("Health insurance unlocks at 18.");
  const plan = wealthHealthInsurancePlans.find(p => p.id === planId);
  if (!plan) return;
  if (plan.id !== "none" && state.money < plan.premium) return addToast(`First premium requires ${money(plan.premium)}.`);
  if (plan.id !== "none") state.money -= plan.premium;
  state.finance.insurance = plan.id;
  const deltas = plan.id === "none" ? { stress: 3 } : { money: -plan.premium, stress: plan.coverage >= .9 ? -5 : -2 };
  applyDeltas(Object.fromEntries(Object.entries(deltas).filter(([k]) => !["money"].includes(k))));
  addLog(plan.id === "none" ? "You dropped health insurance coverage." : `You enrolled in the ${plan.name}.`, deltas);
  save(); render();
}

// Backwards compatibility for old buttons.
buyInsurance = function() { setHealthInsurance("basic50"); };

function calculateMedicalBill(grossCost) {
  const plan = selectedHealthInsurancePlan();
  const covered = Math.round(Math.max(0, grossCost - plan.deductible) * plan.coverage);
  return Math.max(0, grossCost - covered);
}

goHospital = function() {
  ensureStateShape();
  const grossCost = 4200;
  if (!state.flags.needsHospital) return addToast("You do not need emergency care right now.");
  const outOfPocket = calculateMedicalBill(grossCost);
  const paid = Math.min(state.money, outOfPocket);
  const bill = outOfPocket - paid;
  state.money -= paid;
  state.debt += bill;
  state.flags.needsHospital = false;
  const plan = selectedHealthInsurancePlan();
  const deltas = { money: -paid, debt: bill, health: 32, stress: -18, mentalHealth: 6 };
  applyDeltas({ health: 32, stress: -18, mentalHealth: 6 });
  if (bill) {
    addLog(`Hospital care cost ${money(grossCost)}. Your ${plan.name} reduced it to ${money(outOfPocket)}, and the unpaid ${money(bill)} became debt.`, deltas);
  } else {
    addLog(`Hospital care cost ${money(grossCost)}. Your ${plan.name} reduced your bill to ${money(outOfPocket)}, and you recovered.`, deltas);
  }
  save(); render();
};

function borrowAgainstWealth(amount) {
  ensureStateShape();
  if (state.age < 18) return addToast("Secured borrowing unlocks at 18.");
  const amt = Math.round(Number(amount) || 0);
  const limit = availableCollateral();
  if (!amt || amt > limit) return addToast(`You can currently borrow about ${money(limit)} against savings/brokerage.`);
  state.finance.assetBackedLoan += amt;
  state.money += amt;
  state.finance.creditScore = Math.max(300, (state.finance.creditScore || 650) - Math.ceil(amt / 20000));
  state.finance.wealthLineHistory.unshift({ age: state.age, amount: amt });
  state.finance.wealthLineHistory = state.finance.wealthLineHistory.slice(0, 5);
  addLog(`Borrowed ${money(amt)} against your savings and investments. This can help with a down payment, but interest starts next year.`, { money: amt, assetBackedLoan: amt });
  save(); render();
}

function repayWealthLoan(amount) {
  ensureStateShape();
  let amt = amount === "all" ? Math.min(state.money, state.finance.assetBackedLoan) : Number(amount);
  amt = Math.max(0, Math.min(state.money, state.finance.assetBackedLoan, Math.round(amt || 0)));
  if (!amt) return addToast("No repayment available.");
  state.money -= amt;
  state.finance.assetBackedLoan -= amt;
  state.finance.creditScore = Math.min(850, (state.finance.creditScore || 650) + Math.ceil(amt / 15000));
  addLog(`Repaid ${money(amt)} on your asset-backed loan.`, { money: -amt, assetBackedLoan: -amt });
  save(); render();
}

function openBrokerageAccount() {
  ensureStateShape();
  if (state.age < 18) return addToast("Brokerage accounts unlock at 18.");
  if (state.finance.brokerageOpened) return addToast("Brokerage is already open.");
  const cost = 100;
  if (state.money < cost) return addToast("Opening a brokerage requires $100 cash.");
  state.money -= cost;
  state.finance.brokerageOpened = true;
  addLog("Opened a brokerage account. You can now invest cash instead of only saving it.", { money: -cost, smarts: 1 });
  applyDeltas({ smarts: 1 });
  save(); render();
}

const __ledgerInvestBrokerageBeforeVisual = investBrokerage;
investBrokerage = function(amount) {
  ensureStateShape();
  if (!state.finance.brokerageOpened && state.age >= 18) return addToast("Open a brokerage account first.");
  return __ledgerInvestBrokerageBeforeVisual(amount);
};

function startVenture(id) {
  ensureStateShape();
  const v = entrepreneurshipCatalog.find(x => x.id === id);
  if (!v) return;
  const minAge = Math.min(v.minAge || 18, 21);
  if (state.age < minAge) return addToast(`${v.name} unlocks at age ${minAge}.`);
  if (state.finance.businesses.some(b => b.id === id)) return addToast("You already started that venture.");
  if (state.money < v.startup) return addToast(`Startup cost is ${money(v.startup)}.`);
  state.money -= v.startup;
  state.finance.businesses.push({ id, name: v.name, value: Math.round(v.startup * .75), years: 0, reputation: 10, lastIncome: 0 });
  applyDeltas({ discipline: 1, confidence: 2, stress: 2 });
  addLog(`Started ${v.name}. You paid ${money(v.startup)} in startup costs.`, { money: -v.startup, confidence: 2, stress: 2 });
  save(); render();
}

function workVenture(id) {
  ensureStateShape();
  const b = state.finance.businesses.find(x => x.id === id);
  const v = entrepreneurshipCatalog.find(x => x.id === id);
  if (!b || !v) return;
  const key = `venture_${id}`;
  if (state.actionsTaken[key]) return addToast("You already worked on that business this year.");
  state.actionsTaken[key] = true;
  const stat = v.scaleStat === "iq" ? (state.iq || state.stats.iq || 100) / 2 : (state.stats[v.scaleStat] || 50);
  const gain = Math.max(1, Math.round((stat - 35) / 12) + rand(1, 6));
  b.reputation = clamp((b.reputation || 10) + gain, 0, 100);
  b.value = Math.max(0, Math.round((b.value || 0) * (1 + gain / 100)));
  applyDeltas({ stress: 2, discipline: 1, confidence: 1 });
  addLog(`You worked on ${b.name}. Reputation rose to ${b.reputation}.`, { stress: 2, discipline: 1, confidence: 1 });
  save(); render();
}

function sellVenture(id) {
  ensureStateShape();
  const idx = state.finance.businesses.findIndex(x => x.id === id);
  if (idx < 0) return;
  const b = state.finance.businesses[idx];
  const sale = Math.max(0, Math.round((b.value || 0) * rand(75, 125) / 100));
  state.finance.businesses.splice(idx, 1);
  state.money += sale;
  addLog(`Sold ${b.name} for ${money(sale)}.`, { money: sale, confidence: sale > 25000 ? 3 : 1 });
  applyDeltas({ confidence: sale > 25000 ? 3 : 1 });
  save(); render();
}

function childEntries() {
  return Object.entries(state.relationships || {}).filter(([key, r]) => r && r.role === "Child");
}

function fundChildTrust(childKey, amount) {
  ensureStateShape();
  const child = state.relationships[childKey];
  if (!child || child.role !== "Child") return addToast("Child trust not found.");
  let amt = amount === "max" ? Math.min(state.money, 50000) : Number(amount);
  amt = Math.max(0, Math.min(state.money, Math.round(amt || 0)));
  if (!amt) return addToast("No cash available for the trust.");
  state.money -= amt;
  state.finance.trustFunds[childKey] = (state.finance.trustFunds[childKey] || 0) + amt;
  addLog(`Placed ${money(amt)} into ${child.name}'s trust fund.`, { money: -amt, karma: 2 });
  applyDeltas({ karma: 2 });
  save(); render();
}

const __ledgerAddChildBeforeTrust = addChild;
function partnerIQV1862() {
  try {
    var rels = (state && state.relationships) || {};
    var p = Object.keys(rels).map(function (k) { return rels[k]; }).find(function (r) {
      return r && /partner|spouse|wife|husband|girlfriend|boyfriend|fianc/i.test(String(r.role || ""));
    });
    if (p) {
      var iq = Number(p.iqV1862 || p.iq || p.smarts || p.intelligence) || 0;
      if (!iq) { iq = Math.round(96 + (Math.random() * 24 - 12)); p.iqV1862 = iq; } // stable latent IQ once
      return Math.max(55, Math.min(200, iq));
    }
  } catch (e) {}
  return 100;
}
// Children inherit IQ from both parents (midparent) with regression to the mean + variation,
// so two smart parents tend to have a smart kid. Stored on the child; applied when they become heir.
function childInheritedIQV1862() {
  var parentIQ = Math.max(55, Math.min(200, Number(state.traits && state.traits.iq) || 100));
  var partnerIQ = partnerIQV1862();
  var mid = (parentIQ + partnerIQ) / 2;
  var iq = Math.round(100 + (mid - 100) * 0.72 + (Math.random() * 16 - 8));
  return Math.max(55, Math.min(200, iq));
}
addChild = function() {
  const before = new Set(Object.keys((state && state.relationships) || {}));
  __ledgerAddChildBeforeTrust();
  ensureStateShape();
  Object.keys(state.relationships || {}).forEach(key => {
    if (!before.has(key) && state.relationships[key].role === "Child") {
      state.finance.trustFunds[key] = 0;
      try { state.relationships[key].iqV1862 = childInheritedIQV1862(); } catch (e) {}
    }
  });
};
try { window.childInheritedIQV1862 = childInheritedIQV1862; } catch (e) {}

function attendRecruitingShowcase() {
  ensureStateShape();
  if (state.age < 14 || state.age > 22) return addToast("Recruiting showcases matter most from 14 to 22.");
  const cost = 500;
  if (state.money < cost) return addToast("Showcase travel and fees cost $500.");
  const pack = bestScholarshipPackage();
  const athletic = pack.athletic || { annualAward: 0, score: 0 };
  state.money -= cost;
  const boost = state.stats.athleticism >= 80 ? 8 : state.stats.athleticism >= 65 ? 5 : 2;
  state.stats.popularity = clamp((state.stats.popularity || 50) + boost);
  state.stats.confidence = clamp((state.stats.confidence || 50) + Math.ceil(boost / 2));
  state.finance.nilDeals = Math.max(state.finance.nilDeals || 0, state.age >= 16 && athletic.score >= 78 ? Math.round(athletic.score * 35) : state.finance.nilDeals || 0);
  if (athletic.annualAward > 0) state.school.scholarshipOffer = { type: "Athletic Scholarship", annualAward: athletic.annualAward, fullRide: athletic.fullRide, reason: athletic.reason };
  addLog(`You attended an athletic recruiting showcase. Scouts noticed your profile.`, { money: -cost, popularity: boost, confidence: Math.ceil(boost / 2) });
  save(); render();
}

function signNILDeal() {
  ensureStateShape();
  if (state.age < 16 || state.age > 24) return addToast("NIL-style deals unlock for older student athletes.");
  const pack = bestScholarshipPackage();
  const athletic = pack.athletic || { score: 0 };
  const score = athletic.score + Math.floor((state.stats.popularity || 50) / 4);
  if (score < 75) return addToast("Build athleticism, popularity, and GPA before sponsors care.");
  if (state.actionsTaken.nilDeal) return addToast("You already pitched sponsors this year.");
  state.actionsTaken.nilDeal = true;
  const earnings = Math.round(rand(500, 3500) + Math.max(0, score - 75) * rand(60, 180));
  state.money += earnings;
  state.finance.nilDeals = (state.finance.nilDeals || 0) + earnings;
  addLog(`Signed a small athlete sponsorship/NIL-style deal for ${money(earnings)}.`, { money: earnings, popularity: 2, confidence: 2 });
  applyDeltas({ popularity: 2, confidence: 2 });
  save(); render();
}

