            <div class="money-grid">${budgetCatalog.map(b => `<button class="plan-card ${state.finance.budget === b.id ? "selected" : ""}" onclick="setBudgetStyle('${b.id}')"><div class="plan-title">${b.name}</div><div class="plan-sub">${b.desc}</div><div class="money-chip-row"><span class="money-chip">Save ${Math.round(b.autoSave * 100)}%</span><span class="money-chip">Invest ${Math.round(b.autoInvest * 100)}%</span></div></button>`).join("")}</div>
