    ".hub-overlay.hub-money .v188-pulse-tile{border:1px solid rgba(255,255,255,.10)!important;border-radius:13px!important;padding:12px!important;min-width:0!important;background:linear-gradient(160deg,rgba(255,255,255,.055),rgba(0,0,0,.15))!important}",
    ".hub-overlay.hub-money .v188-pulse-tile.good{border-color:rgba(185,220,138,.35)!important;background:linear-gradient(160deg,rgba(49,75,38,.86),rgba(18,16,13,.98))!important}",
    ".hub-overlay.hub-money .v188-pulse-tile.bad{border-color:rgba(233,146,125,.35)!important;background:linear-gradient(160deg,rgba(78,38,34,.86),rgba(18,16,13,.98))!important}",
    ".hub-overlay.hub-money .v188-pulse-tile.gold{border-color:rgba(240,202,123,.36)!important;background:linear-gradient(160deg,rgba(80,61,33,.86),rgba(18,16,13,.98))!important}",
